      {
        id: 'cpl-m1-l2',
        title: 'Commercial Privileges & Limitations',
        xpReward: 10,
        questions: [
          { id: 'cpl-m1-l2-q1', topic: 'Commercial Regulations', type: 'multiple-choice', text: 'Which of the following can a commercial pilot do that a private pilot cannot?', options: ['Act as PIC for compensation or hire — be paid to fly passengers or cargo', 'Fly in Class A airspace without instrument rating', 'Fly aircraft with higher gross weights without a type rating', 'Fly in IMC without instrument rating'], correctAnswer: 0, explanation: 'The fundamental commercial privilege is compensation for flight services. A commercial pilot may be paid to fly within the scope of the certificate (Part 91 operations and limited Part 135). Private pilots cannot be paid.', reference: '14 CFR 61.133' },
          { id: 'cpl-m1-l2-q2', topic: 'Commercial Regulations', type: 'multiple-choice', text: 'A commercial pilot certificate issued without an aircraft category or class rating limitation means:', options: ['This is not possible — all commercial certificates include at least one category/class rating', 'The pilot may fly any aircraft for hire', 'Only applies to military pilots converting to civilian', 'Category/class ratings are optional for commercial pilots'], correctAnswer: 0, explanation: 'All pilot certificates (including commercial) must include specific category and class ratings. A commercial pilot certificate must list at least one rating (e.g., Airplane Single Engine Land). No certificate is issued without ratings.', reference: '14 CFR 61.5' },
          { id: 'cpl-m1-l2-q3', topic: 'Commercial Regulations', type: 'multiple-choice', text: 'The difference between a commercial pilot certificate and an ATP (Airline Transport Pilot) certificate primarily involves:', options: ['ATP requires higher minimums (1,500 hrs total, first class medical) and is required for PIC of airliners operating under Part 121', 'ATP and commercial are equivalent — ATP is just for international operations', 'ATP requires only 500 hours and is obtainable at the same time as the commercial', 'Commercial allows carrier operations; ATP is for private aviation only'], correctAnswer: 0, explanation: 'ATP requires: 1,500 total hours (reduced to 1,000–1,250 for certain graduates), first class medical, and additional knowledge/practical tests. Part 121 air carriers require ATP for all flight crewmembers in command.', reference: '14 CFR 61.159 / Part 121' },
          { id: 'cpl-m1-l2-q4', topic: 'Commercial Regulations', type: 'multiple-choice', text: 'Under 14 CFR 61.133, a commercial pilot without an instrument rating flying cross-country with passengers for compensation must:', options: ['Limit cross-country flights to no more than 50 NM from departure airport', 'Fly only in Class G airspace', 'Not exceed 10,000 feet MSL', 'Carry an instrument-rated pilot as a passenger observer'], correctAnswer: 0, explanation: 'Commercial pilot without instrument rating: cannot carry passengers for hire on XC flights >50 NM or at night. For hire flying limited to daylight, within 50 NM of departure. These limitations disappear once an instrument rating is added.', reference: '14 CFR 61.133' },
          { id: 'cpl-m1-l2-q5', topic: 'Commercial Regulations', type: 'multiple-choice', text: 'What type of operations does 14 CFR Part 119 regulate?', options: ['Air carrier and commercial operator certificate requirements — who must hold an Air Carrier Certificate', 'All for-hire aviation operations including student pilots', 'Operations of large aircraft only', 'Flight schools and designated examiner operations'], correctAnswer: 0, explanation: 'Part 119 establishes which persons must hold an Air Carrier Certificate and Operations Specifications (OpSpecs). It defines the difference between air carriers (Part 121/135) and commercial operators.', reference: '14 CFR Part 119' },
          { id: 'cpl-m1-l2-q6', topic: 'Commercial Regulations', type: 'multiple-choice', text: 'A commercial pilot is providing compensated sightseeing flights within 25 SM of the departure airport. Under what regulation does this commonly fall?', options: ['Normally Part 135 air tours, except certain air tour operations near national parks may fall under SFAR 73', 'Part 91 — all sightseeing is Part 91 regardless of compensation', 'Part 121 if more than 9 seats are occupied', 'No regulation applies to sightseeing within 25 SM'], correctAnswer: 0, explanation: 'Compensated sightseeing flights generally require Part 135 certification unless a specific exception applies. Special regulations (like SFAR 73 for Grand Canyon air tours) may modify requirements for specific geographic areas.', reference: '14 CFR Part 135 / SFAR 73' },
          { id: 'cpl-m1-l2-q7', topic: 'Commercial Regulations', type: 'multiple-choice', text: 'Aerial work operations that do NOT require an Air Carrier Certificate include:', options: ['Crop dusting (agricultural operations), pipeline patrol, banner towing, and aerial photography under Part 91 with a commercial certificate', 'All operations with paying passengers regardless of mission type', 'Only military contract operations', 'Cargo-only operations under 12,500 lbs max gross weight'], correctAnswer: 0, explanation: 'Aerial work (also called "other than common carriage") operations — crop dusting, pipeline patrol, powerline patrol, banner towing, aerial photography — can be conducted under Part 91 with a commercial certificate, without an Air Carrier Certificate.', reference: '14 CFR 119.1' },
          { id: 'cpl-m1-l2-q8', topic: 'Commercial Regulations', type: 'multiple-choice', text: 'A commercial pilot exercising commercial privileges must have completed a flight review within:', options: ['24 calendar months (same as the private pilot flight review requirement)', '12 calendar months', '36 calendar months for commercial operations', 'No flight review required after passing the commercial practical test'], correctAnswer: 0, explanation: 'The flight review requirement (14 CFR 61.56) applies to all pilots — 24 calendar months. Commercial pilots are not exempt. However, the commercial practical test or a proficiency check counts as a flight review.', reference: '14 CFR 61.56' },
          { id: 'cpl-m1-l2-q9', topic: 'Commercial Regulations', type: 'true-false', text: 'A commercial pilot certificate never expires — once issued, it remains valid for the lifetime of the pilot.', options: ['True', 'False'], correctAnswer: 0, explanation: 'True. Like all FAA pilot certificates, a commercial pilot certificate does not expire. However, the pilot must maintain currency (flight review, medical certificate, recent flight experience) to exercise the privileges of the certificate.', reference: '14 CFR 61.19' },
          { id: 'cpl-m1-l2-q10', topic: 'Commercial Regulations', type: 'true-false', text: 'A commercial pilot may accept payment for giving flight instruction, provided they hold a flight instructor certificate (CFI).', options: ['True', 'False'], correctAnswer: 0, explanation: 'True. A commercial pilot who also holds a CFI certificate may receive compensation for flight instruction. The commercial certificate provides the legal authority to accept payment; the CFI certificate authorizes providing the instruction.', reference: '14 CFR 61.133 / 61.193' }
        ]
      }
